+                            PredicateType::RelatesTo.as_str().to_string(),
+                            vec![format!("cluster_{}", ids1.len()), format!("cluster_{}", ids2.len())],
+                            midpoint,
+                            sim * self.cluster_confidence(ids1.len().min(ids2.len())),
+                            merged_evidence,
+                        );
+                        if prop.confidence >= self.config.min_confidence {
